/* model: 2x50x50x50x50x1 tanh MLP, float32 weights */
void model_forward(const float *in, float *out) {
    static float a[50], z[50];
    int i, j;
    for (i = 0; i < 2; i++) a[i] = in[i];
    for (j = 0; j < 50; j++) {
        float acc = model_b0[j];
        for (i = 0; i < 2; i++) acc += a[i] * model_w0[i * 50 + j];
        z[j] = tanhf(acc);
    }
    for (j = 0; j < 50; j++) a[j] = z[j];
    for (j = 0; j < 50; j++) {
        float acc = model_b1[j];
        for (i = 0; i < 50; i++) acc += a[i] * model_w1[i * 50 + j];
        z[j] = tanhf(acc);
    }
    for (j = 0; j < 50; j++) a[j] = z[j];
    for (j = 0; j < 50; j++) {
        float acc = model_b2[j];
        for (i = 0; i < 50; i++) acc += a[i] * model_w2[i * 50 + j];
        z[j] = tanhf(acc);
    }
    for (j = 0; j < 50; j++) a[j] = z[j];
    for (j = 0; j < 50; j++) {
        float acc = model_b3[j];
        for (i = 0; i < 50; i++) acc += a[i] * model_w3[i * 50 + j];
        z[j] = tanhf(acc);
    }
    for (j = 0; j < 50; j++) a[j] = z[j];
    for (j = 0; j < 1; j++) {
        float acc = model_b4[j];
        for (i = 0; i < 50; i++) acc += a[i] * model_w4[i * 1 + j];
        z[j] = acc;
    }
    for (j = 0; j < 1; j++) a[j] = z[j];
    for (i = 0; i < 1; i++) out[i] = a[i];
}